const upstream = $input.all()[0].json;

let raw;
if (upstream.output && upstream.output[0] && upstream.output[0].content) {
  raw = upstream.output[0].content[0].text;
} else if (upstream.content && upstream.content[0]) {
  raw = upstream.content[0].text;
} else {
  throw new Error('Unexpected upstream shape. Keys: ' + Object.keys(upstream).join(', '));
}

const parsed = JSON.parse(raw);
const webhookBody = $('Webhook').item.json.body;

return [{
  json: {
    ...parsed,
    approved: webhookBody.approved === true,
    recipients: webhookBody.recipients,
    preset: webhookBody.preset
  }
}];
